import React, { useState } from "react";
import ExpenseItem from "./ExpenseItem";
import "./Expenses.css";
import Card from "../UI/Card";
import ExpensesFilter from "../ExpensesFilter/ExpensesFilter";

const Expenses = ({ items }) => {
  const [filteredYear, setFilteredYear] = useState("2020");

  const filterDateHandler = (selectedYear) => {
    setFilteredYear(selectedYear);
  };

  const filteredItems = items.filter((item) => {
    return item.date.getFullYear().toString() === filteredYear;
  });

  let itemsContent = <p></p>

  return (
    <Card className="expenses">
      <ExpensesFilter
        // Passing selected year prop to ExpenseFilter.js
        selected={filteredYear}
        // Getting onChange filter date from ExpenseFilter.js
        filterDateHandler={filterDateHandler}
      />
      {/* If first condition is met it uses part after && */}
      {filteredItems.length === 0 && <p>No expenses found</p>}
      {filteredItems.length > 0 &&
        // Outputs filtered year
        filteredItems.map((expense) => (
          <ExpenseItem
            title={expense.title}
            amount={expense.amount}
            date={expense.date}
            key={expense.id}
          />
        ))}
    </Card>
  );
};

export default Expenses;
